import pytest

def test_happy_path():
    fsm = FSM(TaskState.IDLE)
    fsm.transition(Event.TASK_RECEIVED)
    fsm.transition(Event.DRAFT_READY)
    fsm.transition(Event.APPROVED)
    assert fsm.state == TaskState.DONE

def test_invalid_transition_raises():
    fsm = FSM(TaskState.IDLE)
    with pytest.raises(ValueError):
        fsm.transition(Event.APPROVED)  # cannot approve from IDLE

def test_revision_guard_enforced():
    ctx = {"revision_count": 3}
    result = fire(TaskState.REVIEWING, Event.NEEDS_REVISION, ctx)
    assert result == TaskState.DONE   # guard forces done after 3 revisions

def test_graph_terminates():
    result = graph.invoke({
        "task": "Write a one-line bio.",
        "draft": "",
        "review_notes": "",
        "fsm_state": "PROCESSING",
        "revision_count": 0,
    })
    assert result["fsm_state"] in {"DONE", "ERROR"}
    assert len(result["draft"]) > 0

from enum import Enum, auto

class SuperState(Enum):
    ACTIVE    = auto()   # contains PROCESSING, REVIEWING
    TERMINAL  = auto()   # contains DONE, ERROR

class SubState(Enum):
    PROCESSING = auto()
    REVIEWING  = auto()
    DONE       = auto()
    ERROR      = auto()

SUPER_MAP = {
    SubState.PROCESSING: SuperState.ACTIVE,
    SubState.REVIEWING:  SuperState.ACTIVE,
    SubState.DONE:       SuperState.TERMINAL,
    SubState.ERROR:      SuperState.TERMINAL,
}

def is_terminal(state: SubState) -> bool:
    return SUPER_MAP[state] == SuperState.TERMINAL

# Any ACTIVE sub-state can transition to ERROR on llm_error
# instead of repeating this in every row of the transition table:
def fire_hfsm(current: SubState, event: Event, context: dict) -> SubState:
    if event == Event.LLM_ERROR and not is_terminal(current):
        return SubState.ERROR    # super-state transition
    return fire(current, event, context)  # normal sub-state transition
